class Solution:
    def topStudents(self, positive_feedback, negative_feedback, report, student_id, k):
        word_type = {}
        for w in positive_feedback:
            word_type[w] = 1
        for w in negative_feedback:
            word_type[w] = -1
        scores = {}
        for sid, sentence in zip(student_id, report):
            s = 0
            for w in sentence.split():
                t = word_type.get(w, 0)
                if t == 1:
                    s += 3
                elif t == -1:
                    s -= 1
            scores[sid] = s
        remaining = list(scores.items())
        result = []
        for _ in range(k):
            best = None
            for sid, sc in remaining:
                if best is None or sc > best[1] or (sc == best[1] and sid < best[0]):
                    best = (sid, sc)
            result.append(best[0])
            remaining.remove(best)
        return result

